type DSU struct {
	parent []int64
	rank   []int64
}

func NewDSU(n int64) *DSU {
	parent := make([]int64, n)
	rank := make([]int64, n)
	for i := int64(0); i < n; i++ {
		parent[i] = i
		rank[i] = 1
	}
	return &DSU{parent: parent, rank: rank}
}

func (d *DSU) find(x int64) int64 {
	if d.parent[x] != x {
		d.parent[x] = d.find(d.parent[x])
	}
	return d.parent[x]
}

func (d *DSU) union(x, y int64) {
	xRoot := d.find(x)
	yRoot := d.find(y)
	if xRoot == yRoot {
		return
	}
	if d.rank[xRoot] < d.rank[yRoot] {
		d.parent[xRoot] = yRoot
	} else {
		d.parent[yRoot] = xRoot
		if d.rank[xRoot] == d.rank[yRoot] {
			d.rank[xRoot]++
		}
	}
}

func solve(n int64, edges [][]int64, k int64) int64 {
	max_w := int64(0)
	for _, e := range edges {
		if e[2] > max_w {
			max_w = e[2]
		}
	}
	low := int64(0)
	high := max_w
	ans := max_w
	for low <= high {
		mid := (low + high) / 2
		dsu := NewDSU(n)
		for _, e := range edges {
			if e[2] <= mid {
				dsu.union(e[0], e[1])
			}
		}
		roots := make(map[int64]bool)
		for i := int64(0); i < n; i++ {
			roots[dsu.find(i)] = true
		}
		cnt := len(roots)
		if cnt <= k {
			ans = mid
			high = mid - 1
		} else {
			low = mid + 1
		}
	}
	return ans
}
